+/// Platform detection for skip evaluation
+const current_platform: []const u8 = switch (builtin.os.tag) {
+    .windows => "win32",
+    .macos => "darwin",
+    .linux => "linux",
+    .freebsd, .openbsd, .netbsd => "bsd",
+    .wasi => "wasi",
+    else => "unknown",
+};
